Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
  if (!done) {
    doneLackingErr = new Error('no done callback supplied')
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
        var loop = true, cbed = false
        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              loop = false
              if(done) done(end === true ? null : end)
                 <PLACEHOLDER>

                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      cb = err, err = true
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-                 else if(end && end !== true) {
In the mutated code, <PLACEHOLDER> has the value:

+                 else if(end || end !== true) {


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-e973656/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is:
- Original: `else if(end && end !== true)` - triggers when `end` is truthy AND not exactly `true`
- Mutated: `else if(end || end !== true)` - triggers when `end` is truthy OR not exactly `true`

The key difference: with the mutation, when `end === null` (falsy), `null !== true` is `true`, so the condition becomes `false || true = true`, which would incorrectly enter the error branch even when there's no error.

Wait, let me re-read the context. The condition is inside `if(end = end || abort)` - so `end` has already been assigned. If `end` is falsy (like `null` or `undefined`), the outer `if` wouldn't be entered. So `end` is truthy at this point.

The real difference: when `end === true` (normal stream end):
- Original: `true && true !== true` = `true && false` = `false` → skip the error block
- Mutated: `true || true !== true` = `true || false` = `true` → enter the error block (incorrectly!)

So with the mutation, when a stream ends normally (`end === true`), it would still try to `console.warn` and `throw end` even though `done` was already called. But wait, if `done` is provided, the code does `done(end === true ? null : end)` and then falls through to the `else if`. 

Actually looking more carefully: if `done` is provided, it calls `done(null)` for normal end, then the `else if` is checked. With mutation, `end === true` would trigger `throw end` (throwing `true`).

So the test should: provide a `done` callback, have the stream end normally (`true`), and verify no error is thrown.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink", () => {
  it("should not throw when stream ends normally (end === true) even when done callback is provided", () => {
    // Create a simple pull-stream source that ends immediately
    function source(end: any, cb: (end: any, data?: any) => void) {
      if (end) return cb(end);
      // End the stream normally on first read
      cb(true);
    }

    const done = jest.fn();

    // If the mutation is present, this will throw because:
    // end === true, and (true || true !== true) = (true || false) = true
    // which causes `throw end` to be executed
    expect(() => {
      const sink = drain(null, done);
      sink(source);
    }).not.toThrow();

    // Also verify done was called with null (normal end)
    expect(done).toHaveBeenCalledWith(null);
  });
});
```

Wait, but `doneLackingErr` is only set when `!done`. Since we're providing `done`, `doneLackingErr` would be `undefined`. So `console.warn(undefined)` and `throw end` (throwing `true`). The throw would still happen.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink", () => {
  it("should not throw when stream ends normally with a done callback provided", () => {
    function source(end: any, cb: (end: any, data?: any) => void) {
      if (end) return cb(end);
      cb(true);
    }

    const done = jest.fn();

    expect(() => {
      const sink = drain(null, done);
      sink(source);
    }).not.toThrow();

    expect(done).toHaveBeenCalledWith(null);
  });
});
```

Let me re-analyze the mutation more carefully.

The code structure is:
```javascript
if(end = end || abort) {
  loop = false
  if(done) done(end === true ? null : end)
  else if(end && end !== true) {  // original
  // else if(end || end !== true) {  // mutated
    console.warn(doneLackingErr)
    throw end
  }
}
```

The `else if` only runs when `done` is NOT provided (it's `else if` after `if(done)`).

When `done` is NOT provided:
- `end === true` (normal end): Original: `true && false = false` → no throw. Mutated: `true || false = true` → throws!
- `end` is an Error: Original: `true && true = true` → throws. Mutated: `true || true = true` → throws.

So the test needs NO `done` callback, and the stream should end normally with `true`.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink", () => {
  it("should not throw when stream ends normally and no done callback is provided", () => {
    function source(end: any, cb: (end: any, data?: any) => void) {
      if (end) return cb(end);
      cb(true);
    }

    expect(() => {
      const sink = drain(null);
      sink(source);
    }).not.toThrow();
  });
});
```
